import React, {useState, useEffect} from 'react';
import { useHistory, useParams } from 'react-router-dom';
import Info from './Info';
import '../scss/Detail.scss'

function Detail(props){
  const { id } = useParams();
  const [show, setShow] = useState(true)
  const 찾은상품 = props.shoes.find(상품 => 상품.id === Number(id) );
  const history = useHistory();

  useEffect(() => {
    let 타이머 = setInterval(() => {
      setShow(false)
    },2000)
    return ()=> {clearTimeout(타이머)}
  },[show]);

  const oder = () => {
    const newA = [...props.재고];
    props.재고변경([ newA[0] - 1] ) 
  };
  const backkey = (e) => {
    e.preventDefault();
    history.push('/');
  };
  return(
        <div className="container">
            {
              show ? <div className="my-alert-yell">제고가 얼마 남지 않았습니다.</div> : null
            }
            <div className="row">
              <div className="col-md-6">
                <img src={찾은상품.img} width="100%" />
              </div>
              <div className="col-md-6 mt-4">
                <h4 className="pt-5">{찾은상품.title}</h4>
                <p>{찾은상품.content}</p>
                <p>{찾은상품.price}</p>
                <Info 재고={props.재고}/>
                <button className="btn btn-danger" onClick={oder}>주문하기</button> 
                <button className="btn btn-danger" onClick={backkey}>뒤로가기</button> 
              </div>
            </div> 
      </div> 
  );
};

export default Detail;